#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    long long shortestPath(int n, vector<vector<int>>& edges, int S, int T) {
        vector<vector<pair<int,int>>> adj(n+1);
        for (auto &e : edges) {
            int u = e[0], v = e[1], w = e[2];
            adj[u].push_back({v,w});
            adj[v].push_back({u,w});
        }
        const long long INF = LLONG_MAX/4;
        vector<long long> dist(n+1, INF);
        dist[S] = 0;
        using P = pair<long long,int>;
        priority_queue<P, vector<P>, greater<P>> pq;
        pq.push({0, S});
        while (!pq.empty()) {
            auto _tmp_binding_0 = pq.top(); auto d = _tmp_binding_0.first; auto u = _tmp_binding_0.second; pq.pop();
            if (d != dist[u]) continue;
            if (u == T) break;
            for (auto &pr : adj[u]) {
                int v = pr.first; int w = pr.second;
                long long nd = d + w;
                if (nd < dist[v]) {
                    dist[v] = nd;
                    pq.push({nd, v});
                }
            }
        }
        return dist[T]==INF ? -1 : dist[T];
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n; if(!(cin>>n)) return 0;
    int m; cin>>m;
    vector<vector<int>> edges(m, vector<int>(3));
    for(int i=0;i<m;++i){
        cin>>edges[i][0]>>edges[i][1]>>edges[i][2];
    }
    int S,T; cin>>S>>T;
    Solution sol;
    long long ans = sol.shortestPath(n, edges, S, T);
    cout<<ans<<"\n";
    return 0;
}
